const target = $('Emit control-plane repo').item.json;
const resp = $input.item.json;
const commit = Array.isArray(resp) ? resp[0] : resp;
const sha = commit?.sha || '';
return { json: {
  ownerRepo: target.ownerRepo,
  sourceRepo: target.sourceRepo,
  currentSha: sha,
  shortSha: sha ? sha.substring(0, 7) : '',
  latestCommitUrl: commit?.html_url || '',
  latestCommitMessage: String(commit?.commit?.message || '').split('\n')[0],
  event: 'latest_commit_loaded',
  testSafe: true,
  noMessages: true,
  noWrites: true
}};

// Detect docs/plans/*.plan.md changed files from real GitHub commit details.
const commit = $input.first().json;
const latest = $('Prepare latest control-plane commit').first().json;
const files = Array.isArray(commit.files) ? commit.files : [];
const planFiles = files.filter((f) => {
  const name = String(f.filename || '');
  return /^docs\/plans\/[^/]+\.plan\.md$/.test(name);
});
if (!planFiles.length) {
  return [{ json: {
    event: 'no_plan_detected',
    repo: latest.ownerRepo,
    commitSha: latest.currentSha,
    shortSha: latest.shortSha,
    latestCommitUrl: latest.latestCommitUrl,
    latestCommitMessage: latest.latestCommitMessage,
    changedFileCount: files.length,
    changedFiles: files.map(f => f.filename).slice(0, 30),
    gate: 'C-real-api-plan-detect-test-safe',
    noMessages: true,
    noWrites: true
  }}];
}
return planFiles.map((f) => ({ json: {
  event: 'plan_detected',
  repo: latest.ownerRepo,
  commitSha: latest.currentSha,
  shortSha: latest.shortSha,
  latestCommitUrl: latest.latestCommitUrl,
  latestCommitMessage: latest.latestCommitMessage,
  planPath: f.filename,
  fileStatus: f.status || '',
  additions: f.additions ?? null,
  deletions: f.deletions ?? null,
  changes: f.changes ?? null,
  gate: 'C-real-api-plan-detect-test-safe',
  nextGate: 'Gate D message delivery not authorized',
  noMessages: true,
  noWrites: true
}}));
